// Extract batches array and runId from the API response
const response = $input.first().json;
const runId = response.data.runId;
const batches = response.data.batches;

// Return each batch as a separate item with runId attached
return batches.map(batch => ({
  json: {
    runId: runId,
    templateId: batch.templateId,
    context: batch.context,
    structure: batch.structure,
    domain: batch.domain
  }
}));

// n8n Code Node: Parse Claude API output to clean JSON + token cost
// Mode: Run Once for All Items

// ─── TOKEN PRICING (per 1M tokens, USD) ──────────────────────────
const PRICING = {
  'claude-haiku-4-5-20251001':  { input: 0.80,  output: 4.00  },
  'claude-sonnet-4-6':          { input: 3.00,  output: 15.00 },
  'claude-opus-4-6':            { input: 15.00, output: 75.00 },
  'default':                    { input: 3.00,  output: 15.00 }
};

// ─── EXTRACT TEXT ─────────────────────────────────────────────────
const response  = $input.first().json;
const rawOutput = response.content?.[0]?.text || '';

if (!rawOutput) {
  return [{
    json: {
      success: false,
      error: 'No text content found in Claude response',
      raw: response
    }
  }];
}

// ─── PARSE JSON ───────────────────────────────────────────────────
let parsed;

try {
  // Step 1: Direct parse
  parsed = JSON.parse(rawOutput);

} catch (e) {
  try {
    // Step 2: Strip markdown code fences (```json ... ```)
    const stripped = rawOutput
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/```\s*$/i, '')
      .trim();

    parsed = JSON.parse(stripped);

  } catch (e2) {
    try {
      // Step 3: Regex extract { ... } as last resort
      const match = rawOutput.match(/\{[\s\S]*\}/);
      if (!match) throw new Error('No JSON object found');
      parsed = JSON.parse(match[0]);

    } catch (e3) {
      return [{
        json: {
          success: false,
          error: 'Failed to parse LLM output as JSON',
          raw: rawOutput
        }
      }];
    }
  }
}

// ─── VALIDATE REQUIRED FIELDS ─────────────────────────────────────
const requiredFields = ['questionText', 'options', 'correctAnswer', 'explanation','templateId'];
const missingFields  = requiredFields.filter(f => !parsed[f]);

if (missingFields.length > 0) {
  return [{
    json: {
      success: false,
      error: `Missing required fields: ${missingFields.join(', ')}`,
      raw: rawOutput,
      parsed
    }
  }];
}

// ─── CALCULATE TOKEN COST ──────────────────────────────────────────
const model        = response.model || 'default';
const inputTokens  = response.usage?.input_tokens  || 0;
const outputTokens = response.usage?.output_tokens || 0;
const totalTokens  = inputTokens + outputTokens;

const rates      = PRICING[model] || PRICING['default'];
const inputCost  = (inputTokens  / 1_000_000) * rates.input;
const outputCost = (outputTokens / 1_000_000) * rates.output;
const totalCost  = inputCost + outputCost;

// ─── RETURN CLEAN OUTPUT ───────────────────────────────────────────
return [{
  json: {
    success:        true,
    // Question fields
    questionText:   parsed.questionText,
    options:        parsed.options,
    correctAnswer:  parsed.correctAnswer,
    explanation:    parsed.explanation,
    templateId: parsed.templateId,
    tags:           parsed.tags           || [],
    estimatedTime:  parsed.estimatedTime  || null,
    parameters:     parsed.parameters     || null,
    computedAnswer: parsed.computedAnswer || null,
    // Token usage
    model:          model,
    totalTokens:    totalTokens,
    // Cost (USD)
    totalCostUSD:   parseFloat(totalCost.toFixed(6))
  }
}];

